/**
 * SummaryPanel - Live order summary panel
 * Displays order details and totals
 * Pinned on right side (desktop) or below form (mobile)
 */

import { ServiceType } from '@/src/types'
import { formatCurrency } from '@/src/utils/formatting'

interface SummaryPanelProps {
  outletName?: string
  recipientName?: string
  recipientAddress?: string
  itemCount: number
  distance: number | null
  serviceType: ServiceType
  shippingFee: number
  weight: number
  isFragile: boolean
}

export function SummaryPanel({
  outletName,
  recipientName,
  recipientAddress,
  itemCount,
  distance,
  serviceType,
  shippingFee,
  weight,
  isFragile,
}: SummaryPanelProps) {
  return (
    <div className="bg-white rounded-lg shadow p-6 sticky top-6 h-fit">
      <h3 className="text-lg font-semibold text-gray-900 mb-6">Order Summary</h3>

      <div className="space-y-4">
        {/* Outlet */}
        {outletName && (
          <div>
            <p className="text-sm text-gray-600">From</p>
            <p className="font-medium text-gray-900">{outletName}</p>
          </div>
        )}

        {/* Recipient */}
        {recipientName && (
          <div>
            <p className="text-sm text-gray-600">To</p>
            <p className="font-medium text-gray-900">{recipientName}</p>
            {recipientAddress && (
              <p className="text-sm text-gray-600 mt-1">{recipientAddress}</p>
            )}
          </div>
        )}

        {/* Items */}
        {itemCount > 0 && (
          <div className="pt-4 border-t border-gray-200">
            <p className="text-sm text-gray-600">Items</p>
            <p className="font-medium text-gray-900">{itemCount} item{itemCount !== 1 ? 's' : ''}</p>
          </div>
        )}

        {/* Package Details */}
        {(weight > 0 || isFragile) && (
          <div className="pt-4 border-t border-gray-200">
            <p className="text-sm text-gray-600">Package</p>
            <div className="space-y-1">
              {weight > 0 && (
                <p className="text-sm text-gray-900">Weight: {weight} kg</p>
              )}
              {isFragile && (
                <p className="text-sm text-red-600 font-medium">⚠ Fragile</p>
              )}
            </div>
          </div>
        )}

        {/* Distance & Service Type */}
        {distance !== null && (
          <div className="pt-4 border-t border-gray-200">
            <p className="text-sm text-gray-600">Service Type</p>
            <p className="font-medium text-gray-900 capitalize">{serviceType}</p>
            <p className="text-sm text-gray-600 mt-2">Distance: {distance.toFixed(1)} km</p>
          </div>
        )}

        {/* Shipping Fee */}
        <div className="pt-4 border-t border-gray-200">
          <p className="text-sm text-gray-600">Shipping Fee</p>
          <p className="text-2xl font-bold text-[#ED0577]">{formatCurrency(shippingFee)}</p>
        </div>
      </div>
    </div>
  )
}

export default SummaryPanel
